def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid, copy=True)
    h, w = grid.shape
    out = np.zeros_like(grid)

    visited = np.zeros((h, w), dtype=bool)
    dirs = [(1, 0), (-1, 0), (0, 1), (0, -1)]

    for r in range(h):
        for c in range(w):
            if grid[r, c] == 0 or visited[r, c]:
                continue

            color = grid[r, c]
            stack = [(r, c)]
            visited[r, c] = True
            cells = []

            while stack:
                x, y = stack.pop()
                cells.append((x, y))
                for dx, dy in dirs:
                    nx, ny = x + dx, y + dy
                    if 0 <= nx < h and 0 <= ny < w and not visited[nx, ny] and grid[nx, ny] == color:
                        visited[nx, ny] = True
                        stack.append((nx, ny))

            max_r = max(x for x, y in cells)
            max_c = max(y for x, y in cells)

            for x, y in cells:
                if x == max_r or y == max_c:
                    out[x, y] = color
                else:
                    ny = y + 1
                    if ny < w:
                        out[x, ny] = color

    return out

