        step = dc

    out = np.zeros_like(grid)

    if axis == "col":
        cols = [c1, c2]
        cols.sort()
        for c in range(cols[0], w, step):
            out[:, c] = v1 if c == c1 else v2 if c == c2 else (v1 if (c - c1) % step == 0 else 0)
        # Ensure the two clue columns use their respective colors and repeat alternation.
        for c in range(0, w):
            if (c - c1) % step == 0:
