def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid)
    h, w = grid.shape

    # Find all-black separator rows and columns
    row_nonzero = np.any(grid != 0, axis=1)
    col_nonzero = np.any(grid != 0, axis=0)

    sep_rows = np.where(~row_nonzero)[0]
    sep_cols = np.where(~col_nonzero)[0]

    # Determine panel boundaries from separator bands
    row_bounds = []
    start = 0
    for r in sep_rows:
        if r > start:
            row_bounds.append((start, r))
        start = r + 1
    if start < h:
        row_bounds.append((start, h))

    col_bounds = []
    start = 0
    for c in sep_cols:
        if c > start:
            col_bounds.append((start, c))
        start = c + 1
    if start < w:
        col_bounds.append((start, w))

    # Expect 2x2 panels
    if len(row_bounds) < 2 or len(col_bounds) < 2:
        return grid.copy()

    panels = []
    for rb in row_bounds[:2]:
        row_panels = []
        for cb in col_bounds[:2]:
            panel = grid[rb[0]:rb[1], cb[0]:cb[1]]
            row_panels.append(panel)
        panels.append(row_panels)

    top_left, top_right = panels[0][0], panels[0][1]
    bottom_left, bottom_right = panels[1][0], panels[1][1]

    def nonzero_color(panel):
        vals = panel[panel != 0]
        if vals.size == 0:
            return 0
        uniq = np.unique(vals)
        return int(uniq[0])

    ref_color = nonzero_color(top_left)
    if nonzero_color(top_right) != ref_color:
        # If top panels are not identical, still use the most common nonzero color among them
        colors = []
        for p in [top_left, top_right]:
            vals = p[p != 0]
            if vals.size:
                colors.extend(list(vals))
        if colors:
            ref_color = int(np.bincount(np.array(colors)).argmax())

    bl_color = nonzero_color(bottom_left)
    br_color = nonzero_color(bottom_right)

    # Select the bottom panel whose color differs from the top reference color
    if bl_color != ref_color and br_color == ref_color:
        out = bottom_left
    elif br_color != ref_color and bl_color == ref_color:
        out = bottom_right
    else:
        # Fallback: choose the panel with color different from reference, or left by default
        out = bottom_left if bl_color != ref_color else bottom_right

    return np.array(out)

