def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid, copy=True)
    h, w = grid.shape

    # Find the smallest repeating horizontal period by comparing columns modulo p.
    def compatible_period(p):
        for c in range(w):
            ref = c % p
            a = grid[:, c]
            b = grid[:, ref]
            mask = (a != 0) & (b != 0)
            if np.any(a[mask] != b[mask]):
                return False
        return True

    period = w
    for p in range(1, w + 1):
        if w % p == 0 and compatible_period(p):
            period = p
            break

    # Reconstruct each template column from all compatible columns in its class.
    templates = np.zeros((h, period), dtype=grid.dtype)
    for r in range(h):
        for c in range(period):
            vals = grid[r, c:w:period]
            vals = vals[vals != 0]
            if vals.size:
                templates[r, c] = vals[0]

    # Fill the whole grid by repeating the completed templates.
    out = np.zeros_like(grid)
    for c in range(w):
        out[:, c] = templates[:, c % period]

    return out

