def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    g = np.array(input_grid, copy=True)
    h, w = g.shape
    out = np.zeros_like(g)

    # Find connected components of non-zero cells
    visited = np.zeros((h, w), dtype=bool)
    dirs = [(1, 0), (-1, 0), (0, 1), (0, -1)]

    for r in range(h):
        for c in range(w):
            if g[r, c] == 0 or visited[r, c]:
                continue

            # BFS/DFS for component
            stack = [(r, c)]
            visited[r, c] = True
            comp = []
            while stack:
                x, y = stack.pop()
                comp.append((x, y))
                for dx, dy in dirs:
                    nx, ny = x + dx, y + dy
                    if 0 <= nx < h and 0 <= ny < w and not visited[nx, ny] and g[nx, ny] != 0:
                        visited[nx, ny] = True
                        stack.append((nx, ny))

            comp_set = set(comp)

            # Mark cells that belong to any 2x2 all-filled block as teal
            teal = set()
            for x, y in comp:
                for ox in (0, -1):
                    for oy in (0, -1):
                        x0, y0 = x + ox, y + oy
                        if 0 <= x0 < h - 1 and 0 <= y0 < w - 1:
                            cells = [(x0, y0), (x0 + 1, y0), (x0, y0 + 1), (x0 + 1, y0 + 1)]
                            if all((a, b) in comp_set for a, b in cells):
                                teal.update(cells)

            # Remaining component cells are corridor/bridge cells
            for x, y in comp:
                out[x, y] = 8 if (x, y) in teal else 2

    return out

