def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid)
    h, w = grid.shape

    # Find the most likely frame color: a color that forms a full rectangle border.
    best = None  # (area, top, left, bottom, right, color)
    colors = [c for c in np.unique(grid) if c != 0]

    for c in colors:
        rows, cols = np.where(grid == c)
        if len(rows) == 0:
            continue
        top, bottom = rows.min(), rows.max()
        left, right = cols.min(), cols.max()

        # Check if the border of this bounding box is monochrome c
        if bottom - top < 2 or right - left < 2:
            continue

        border_ok = True
        if not np.all(grid[top, left:right + 1] == c):
            border_ok = False
        if not np.all(grid[bottom, left:right + 1] == c):
            border_ok = False
        if not np.all(grid[top:bottom + 1, left] == c):
            border_ok = False
        if not np.all(grid[top:bottom + 1, right] == c):
            border_ok = False

        if border_ok:
            area = (bottom - top + 1) * (right - left + 1)
            cand = (area, top, left, bottom, right, c)
            if best is None or cand[0] > best[0]:
                best = cand

    if best is None:
        return np.zeros((0, 0), dtype=grid.dtype)

    _, top, left, bottom, right, c = best
    return grid[top + 1:bottom, left + 1:right]

