def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    g = np.array(input_grid)
    h, w = g.shape

    # Find the most likely delimiter color: a non-zero color forming a rectangle border.
    colors, counts = np.unique(g[g != 0], return_counts=True)
    if len(colors) == 0:
        return g.copy()

    best = None
    best_score = -1

    for c in colors:
        rows = np.where(np.any(g == c, axis=1))[0]
        cols = np.where(np.any(g == c, axis=0))[0]
        if len(rows) < 2 or len(cols) < 2:
            continue

        top, bottom = rows[0], rows[-1]
        left, right = cols[0], cols[-1]

        # Check border consistency: top/bottom rows and left/right cols should be mostly c.
        top_count = np.sum(g[top, left:right + 1] == c)
        bottom_count = np.sum(g[bottom, left:right + 1] == c)
        left_count = np.sum(g[top:bottom + 1, left] == c)
        right_count = np.sum(g[top:bottom + 1, right] == c)

        score = top_count + bottom_count + left_count + right_count
        if score > best_score:
            best_score = score
            best = (top, bottom, left, right, c)

    if best is None:
        return g.copy()

    top, bottom, left, right, c = best

    # Extract interior excluding the delimiter border.
    if bottom - top <= 1 or right - left <= 1:
        return np.empty((0, 0), dtype=g.dtype)

    return g[top + 1:bottom, left + 1:right]

