def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid, dtype=int)
    n, m = grid.shape
    out = np.zeros((n, m), dtype=int)

    # Find the non-red color and the 2x2 marker positions
    color = None
    red_positions = np.argwhere(grid == 2)
    for r, c in red_positions:
        if grid[r, c] != 2:
            continue
    nonzero_nonred = np.argwhere((grid != 0) & (grid != 2))
    if len(nonzero_nonred) > 0:
        color = int(grid[nonzero_nonred[0][0], nonzero_nonred[0][1]])
    else:
        return out

    # Determine the 2x2 marker bounding box
    rows = red_positions[:, 0]
    cols = red_positions[:, 1]
    r0, r1 = rows.min(), rows.max()
    c0, c1 = cols.min(), cols.max()

    # Identify the diagonal direction from the red cells' corner position
    # The red cells occupy 3 cells of a 2x2 block; the missing corner indicates direction.
    block = grid[r0:r0+2, c0:c0+2]
    missing = None
    for i in range(2):
        for j in range(2):
            if block[i, j] != 2:
                missing = (i, j)
                break
        if missing is not None:
            break

    # Map missing corner to direction of propagation
    # missing top-left -> southeast, top-right -> southwest, bottom-left -> northeast, bottom-right -> northwest
    if missing == (0, 0):
        dr, dc = 1, 1
    elif missing == (0, 1):
        dr, dc = 1, -1
    elif missing == (1, 0):
        dr, dc = -1, 1
    else:  # (1, 1)
        dr, dc = -1, -1

    # Start from the 2x2 block filled with color
    start_r, start_c = r0, c0
    for step in range(max(n, m)):
        rr = start_r + step * dr
        cc = start_c + step * dc
        for i in range(2):
            for j in range(2):
                r = rr + i
                c = cc + j
                if 0 <= r < n and 0 <= c < m:
                    out[r, c] = color

    return out

