def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    g = np.array(input_grid, copy=False)
    h, w = g.shape
    out = np.zeros((h, w), dtype=int)

    vals, counts = np.unique(g[g != 0], return_counts=True)
    if len(vals) == 0:
        return out

    c = int(vals[np.argmax(counts)])

    coords = np.argwhere(g == c)
    if coords.size == 0:
        return out

    r0, c0 = coords.min(axis=0)
    r1, c1 = coords.max(axis=0)

    # Detect the 2x2 seed square of color c, possibly with one red marker inside.
    # Use the bounding box of the nonzero cluster if it is 2x2 or 2x2-ish.
    # Find a 2x2 region containing at least three cells of color c or one red marker.
    seed_r = seed_c = None
    for r in range(max(0, r1 - 1), min(h - 1, r0 + 1) + 1):
        for ccol in range(max(0, c1 - 1), min(w - 1, c0 + 1) + 1):
            if r + 1 < h and ccol + 1 < w:
                block = g[r:r+2, ccol:ccol+2]
                if np.sum(block == c) >= 3 or np.any((block != 0) & (block != c)):
                    seed_r, seed_c = r, ccol
                    break
        if seed_r is not None:
            break

    if seed_r is None:
        # Fallback: use bounding box
        seed_r, seed_c = r0, c0

    # Determine which corners are marked by red cells in the 2x2 block.
    block = g[seed_r:seed_r+2, seed_c:seed_c+2]
    red_positions = []
    for i in range(block.shape[0]):
        for j in range(block.shape[1]):
            if block[i, j] != 0 and block[i, j] != c:
                red_positions.append((i, j))

    # If no explicit red marker, infer from the shape of the 2x2 block:
    # use all corners that are not already color c as markers.
    if not red_positions:
        for i in range(2):
            for j in range(2):
                if seed_r + i < h and seed_c + j < w and g[seed_r + i, seed_c + j] != c:
                    red_positions.append((i, j))

    # For each marked corner, extend the three diagonals of the solid 2x2 square
    # outward in the corresponding diagonal direction.
    for i, j in red_positions:
        if i == 0 and j == 0:  # top-left -> northwest
            for d in range(max(h, w)):
                rr, cc = seed_r - d, seed_c - d
                if 0 <= rr < h and 0 <= cc < w:
                    out[rr, cc] = c
        elif i == 0 and j == 1:  # top-right -> northeast
            for d in range(max(h, w)):
                rr, cc = seed_r - d, seed_c + 1 + d
                if 0 <= rr < h and 0 <= cc < w:
                    out[rr, cc] = c
        elif i == 1 and j == 0:  # bottom-left -> southwest
            for d in range(max(h, w)):
                rr, cc = seed_r + 1 + d, seed_c - d
                if 0 <= rr < h and 0 <= cc < w:
                    out[rr, cc] = c
        elif i == 1 and j == 1:  # bottom-right -> southeast
            for d in range(max(h, w)):
                rr, cc = seed_r + 1 + d, seed_c + 1 + d
                if 0 <= rr < h and 0 <= cc < w:
                    out[rr, cc] = c

    return out

