def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    g = np.array(input_grid, dtype=int)
    h, w = g.shape
    out = np.zeros_like(g)

    ys, xs = np.where(g != 0)
    if len(ys) == 0:
        return out

    color = None
    cells = []
    for y, x in zip(ys, xs):
        v = g[y, x]
        if v == 2:
            cells.append((y, x))
        else:
            color = v

    if color is None:
        return out

    if len(cells) == 0:
        return out

    ys2 = [y for y, x in cells]
    xs2 = [x for y, x in cells]
    y0, x0 = min(ys2), min(xs2)

    # Determine the 2x2 object's top-left corner by finding the 2x2 block
    # containing the red cells and the non-red color cell.
    # The object is assumed to occupy a 2x2 area with one colored cell and red cells.
    # Use the bounding box of nonzero cells.
    y0 = min(ys)
    x0 = min(xs)

    # If the nonzero cells are not already in a 2x2 block, infer the 2x2 block
    # from the minimum row/col among them.
    # The colored cell is one of the four positions in that 2x2 block.
    # Red cells indicate which diagonal strip to paint.
    block = g[y0:y0+2, x0:x0+2]
    if block.shape != (2, 2):
        return out

    # Identify the colored cell position within the 2x2 block
    pos = None
    for i in range(2):
        for j in range(2):
            if block[i, j] not in (0, 2):
                pos = (i, j)
                color = block[i, j]
                break
        if pos is not None:
            break

    if pos is None:
        return out

    # Map colored cell position to diagonal strip direction
    # NW cell -> strip to northwest
    # NE cell -> strip to northeast
    # SW cell -> strip to southwest
    # SE cell -> strip to southeast
    i, j = pos

    if (i, j) == (0, 0):  # NW
        for r in range(h):
            for c in range(w):
                if c <= x0 + 1 and r <= y0 + 1 and (x0 - c) == (y0 - r) and (x0 - c) >= 0:
                    out[r, c] = color
        # include the 2x2 block itself
        out[y0:y0+2, x0:x0+2][block != 0] = color
    elif (i, j) == (0, 1):  # NE
        for r in range(h):
            for c in range(w):
                if c >= x0 and r <= y0 + 1 and (c - (x0 + 1)) == (y0 - r) and (c - (x0 + 1)) >= 0:
                    out[r, c] = color
        out[y0:y0+2, x0:x0+2][block != 0] = color
    elif (i, j) == (1, 0):  # SW
        for r in range(h):
            for c in range(w):
                if c <= x0 + 1 and r >= y0 and (x0 - c) == (r - (y0 + 1)) and (x0 - c) >= 0:
                    out[r, c] = color
        out[y0:y0+2, x0:x0+2][block != 0] = color
    else:  # SE
        for r in range(h):
            for c in range(w):
                if c >= x0 and r >= y0 and (c - (x0 + 1)) == (r - (y0 + 1)) and (c - (x0 + 1)) >= 0:
                    out[r, c] = color
        out[y0:y0+2, x0:x0+2][block != 0] = color

    # Ensure all nonzero cells in the original 2x2 object are painted
    for y, x in cells:
        out[y, x] = color
    for y, x in zip(*np.where((g != 0) & (g != 2))):
        out[y, x] = g[y, x]

    return out

