    offset_counts = {}
    second_color = None
    for neigh in all_neigh:
        for di, dj, col in neigh:
            offset_counts[(di, dj, col)] = offset_counts.get((di, dj, col), 0) + 1
    if offset_counts:
        # pick the most frequent offset-color triple
        (best_di, best_dj, second_color), _ = max(offset_counts.items(), key=lambda kv: kv[1])
        offsets = [(di, dj) for (di, dj, col), cnt in offset_counts.items() if col == second_color]
    else:
        return g

    # Apply the pattern around every compartment of the center color:
    # only fill black compartments, leave separators and existing colored compartments unchanged.
    for i in range(R):
        for j in range(C):
