    for p in parts:
        if is_square(p) and len(nonzero_colors(p)) == 1:
            mask = p
        else:
            grid = p
    if mask is None or grid is None:
        # If ambiguous, choose the larger square as mask if it has one color
        for p in parts:
            if len(nonzero_colors(p)) == 1:
                mask = p
        grid = parts[0] if mask is parts[1] else parts[1]

    # If split was vertical, output side = mask side * grid side
    m = mask.shape[0]
    n = grid.shape[0]
    out = np.zeros((m * n, m * n), dtype=int)

    # Copy the colored grid into each block corresponding to a non-zero mask cell
    for i in range(m):
        for j in range(m):
            if mask[i, j] != 0:
                out[i * n:(i + 1) * n, j * n:(j + 1) * n] = grid

    return out

