def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid)
    h, w = grid.shape

    colors = [c for c in np.unique(grid) if c != 0 and c != 8]
    if not colors:
        return np.zeros((h, w), dtype=int)

    # Determine the coarse color grid size by finding a factor pair that can
    # explain the non-8, non-zero cells as one color per block.
    # We infer block size from the teal pattern dimensions.
    # Search all divisors of h and w.
    best = None
    for bh in range(1, h + 1):
        if h % bh != 0:
            continue
        for bw in range(1, w + 1):
            if w % bw != 0:
                continue
            ch, cw = h // bh, w // bw
            # coarse grid should have at least one nonzero color cell
            if ch * cw < len(colors):
                continue
            # Check if each block contains at most one nonzero color and
            # that all nonzero colors are represented.
            ok = True
            seen = set()
            for i in range(ch):
                for j in range(cw):
                    block = grid[i*bh:(i+1)*bh, j*bw:(j+1)*bw]
                    vals = set(np.unique(block)) - {0, 8}
                    if len(vals) > 1:
                        ok = False
                        break
                    if len(vals) == 1:
                        seen |= vals
                if not ok:
                    break
            if ok and seen == set(colors):
                best = (bh, bw, ch, cw)
                break
        if best is not None:
            break

    if best is None:
        # Fallback: use the full grid as pattern with a single color if possible.
        # This should not be needed for valid ARC tasks.
        return np.where(grid == 8, grid, 0)

    bh, bw, ch, cw = best

    # Recover coarse color grid: each block's nonzero non-8 value.
    coarse = np.zeros((ch, cw), dtype=int)
    for i in range(ch):
        for j in range(cw):
            block = grid[i*bh:(i+1)*bh, j*bw:(j+1)*bw]
            vals = [v for v in np.unique(block) if v not in (0, 8)]
            if vals:
                coarse[i, j] = vals[0]

    # Recover teal pattern from the 8-cells in the input.
    pattern = (grid == 8).astype(int)

    # Build output by blockwise product.
    out = np.zeros((ch * bh, cw * bw), dtype=int)
    for i in range(ch):
        for j in range(cw):
            c = coarse[i, j]
            if c == 0:
                continue
            out[i*bh:(i+1)*bh, j*bw:(j+1)*bw] = pattern[i*bh:(i+1)*bh, j*bw:(j+1)*bw] * c

    return out

