        vals = [v for v in grid[r] if v != 0]
        if len(vals) == 1 and vals[0] == 8:
            pattern = grid[r].copy()
            break
        if len(vals) > 0:
            colors.append(grid[r].copy())

    if pattern is None:
        for c in range(cols):
            vals = [grid[r, c] for r in range(rows) if grid[r, c] != 0]
            if len(vals) == 1 and vals[0] == 8:
                pattern = grid[:, c].copy()
                break

