        pattern = np.zeros(cols, dtype=int)

    if not colors:
        for r in range(rows):
            if np.any(grid[r] != 0) and not np.all((grid[r] == 0) | (grid[r] == 8)):
                colors.append(grid[r].copy())

    color_grid = np.array(colors, dtype=int)
    if color_grid.ndim == 1:
        color_grid = color_grid.reshape(1, -1)

    pr = pattern.shape[0]
    cr, cc = color_grid.shape

    out = np.zeros((cr * pr, cc * pr), dtype=int)

    for i in range(cr):
        for j in range(cc):
            color = color_grid[i, j]
            if color == 0:
                continue
