def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    g = np.array(input_grid, copy=True)
    h, w = g.shape
    color = 3
    red = 2

    visited = np.zeros((h, w), dtype=bool)

    def find_rect(r, c):
        if g[r, c] != color or visited[r, c]:
            return None
        # determine maximal rectangle of color starting at (r,c)
        r2 = r
        while r2 < h and g[r2, c] == color:
            r2 += 1
        c2 = c
        while c2 < w and g[r, c2] == color:
            c2 += 1
        # verify rectangle
        for rr in range(r, r2):
            for cc in range(c, c2):
                if g[rr, cc] != color:
                    return None
        return r, r2, c, c2

    rects = []
    for r in range(h):
        for c in range(w):
            if g[r, c] == color and not visited[r, c]:
                rect = find_rect(r, c)
                if rect is not None:
                    r1, r2, c1, c2 = rect
                    visited[r1:r2, c1:c2] = True
                    rects.append(rect)

    for r1, r2, c1, c2 in rects:
        rh = r2 - r1
        rw = c2 - c1

        # locate red cell on outer edge of rectangle
        red_pos = None
        for rr in range(r1, r2):
            for cc in range(c1, c2):
                if g[rr, cc] == red:
                    red_pos = (rr, cc)
                    break
            if red_pos is not None:
                break
        if red_pos is None:
            continue

        rr, cc = red_pos

        # determine which side is marked
        if rr == r1:
            side = 'top'
        elif rr == r2 - 1:
            side = 'bottom'
        elif cc == c1:
            side = 'left'
        else:
            side = 'right'

        if side in ('top', 'bottom'):
            band_half = rh - 1
            left = max(0, cc - band_half)
            right = min(w - 1, cc + band_half)
            if side == 'top':
                start = 0
                end = r1 - 1
            else:
                start = r2
                end = h - 1
            if start <= end:
                for r in range(start, end + 1):
                    for c in range(left, right + 1):
                        g[r, c] = color
                if 0 <= rr < h:
                    for c in range(left, right + 1):
                        g[rr, c] = red
        else:
            band_half = rw - 1
            top = max(0, rr - band_half)
            bottom = min(h - 1, rr + band_half)
            if side == 'left':
                start = 0
                end = c1 - 1
            else:
                start = c2
                end = w - 1
            if start <= end:
                for r in range(top, bottom + 1):
                    for c in range(start, end + 1):
                        g[r, c] = color
                if 0 <= cc < w:
                    for r in range(top, bottom + 1):
                        g[r, cc] = red

    return g

