    h, w = g.shape
    color = int(np.max(g[g != 0])) if np.any(g != 0) else 0

    visited = np.zeros((h, w), dtype=bool)

    def find_component(sr, sc):
        stack = [(sr, sc)]
        visited[sr, sc] = True
        cells = []
        while stack:
            r, c = stack.pop()
            cells.append((r, c))
            for dr, dc in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                nr, nc = r + dr, c + dc
                if 0 <= nr < h and 0 <= nc < w and not visited[nr, nc] and g[nr, nc] != 0:
                    visited[nr, nc] = True
                    stack.append((nr, nc))
        return cells

    comps = []
    for r in range(h):
        for c in range(w):
            if g[r, c] != 0 and not visited[r, c]:
                comps.append(find_component(r, c))

    for cells in comps:
        vals = [g[r, c] for r, c in cells]
        nonzero = [v for v in vals if v != 0]
        if not nonzero:
            continue
        fg = max(set(nonzero), key=nonzero.count)
        rect_cells = [(r, c) for r, c in cells if g[r, c] == fg]
        marker_cells = [(r, c) for r, c in cells if g[r, c] != fg]
        if not rect_cells or not marker_cells:
            continue

        rs = [r for r, c in rect_cells]
        cs = [c for r, c in rect_cells]
        r0, r1 = min(rs), max(rs)
        c0, c1 = min(cs), max(cs)
        rh = r1 - r0 + 1
        rw = c1 - c0 + 1

        mr, mc = marker_cells[0]

        if mr == r0 - 1:  # marker on top
            col_start = mc - (rh - 1)
            col_end = mc + (rh - 1)
            for r in range(0, r0):
                for c in range(max(0, col_start), min(w, col_end + 1)):
                    g[r, c] = fg
            for r in range(0, r0):
                if 0 <= mc < w:
                    g[r, mc] = fg
        elif mr == r1 + 1:  # marker on bottom
            col_start = mc - (rh - 1)
            col_end = mc + (rh - 1)
            for r in range(r1 + 1, h):
                for c in range(max(0, col_start), min(w, col_end + 1)):
                    g[r, c] = fg
            for r in range(r1 + 1, h):
                if 0 <= mc < w:
                    g[r, mc] = fg
        elif mc == c0 - 1:  # marker on left
            row_start = mr - (rw - 1)
            row_end = mr + (rw - 1)
            for c in range(0, c0):
                for r in range(max(0, row_start), min(h, row_end + 1)):
                    g[r, c] = fg
            for c in range(0, c0):
                if 0 <= mr < h:
                    g[mr, c] = fg
        elif mc == c1 + 1:  # marker on right
            row_start = mr - (rw - 1)
            row_end = mr + (rw - 1)
            for c in range(c1 + 1, w):
                for r in range(max(0, row_start), min(h, row_end + 1)):
                    g[r, c] = fg
            for c in range(c1 + 1, w):
                if 0 <= mr < h:
                    g[mr, c] = fg

    return g

