    for c in colors:
        ys, xs = np.where(g == c)
        if len(xs) == 0:
            continue
        r0, r1 = ys.min(), ys.max()
        c0, c1 = xs.min(), xs.max()

        red_pos = np.argwhere(g == 2)
        red_pos = red_pos[(red_pos[:, 0] >= r0) & (red_pos[:, 0] <= r1) &
                          (red_pos[:, 1] >= c0) & (red_pos[:, 1] <= c1)]
        if len(red_pos) == 0:
            continue
        ry, rx = red_pos[0]

        # Determine which side the red cell lies on and the beam direction
        d_top = ry - r0
        d_bottom = r1 - ry
        d_left = rx - c0
        d_right = c1 - rx

        # Prefer the side where the red cell is on the boundary and the opposite side distance is positive
        candidates = []
        if ry == r0:
            candidates.append(("up", d_bottom))
        if ry == r1:
            candidates.append(("down", d_top))
        if rx == c0:
            candidates.append(("left", d_right))
        if rx == c1:
            candidates.append(("right", d_left))

        if not candidates:
            continue

        # Choose the candidate with largest opposite-side distance if ambiguous
        direction, radius = max(candidates, key=lambda t: t[1])

        if direction == "up":
            for y in range(0, ry + 1):
                for x in range(max(0, rx - radius), min(w, rx + radius + 1)):
                    if x == rx:
                        out[y, x] = 2
                    elif out[y, x] == 0:
                        out[y, x] = c
        elif direction == "down":
            for y in range(ry, h):
                for x in range(max(0, rx - radius), min(w, rx + radius + 1)):
                    if x == rx:
                        out[y, x] = 2
                    elif out[y, x] == 0:
                        out[y, x] = c
        elif direction == "left":
            for x in range(0, rx + 1):
                for y in range(max(0, ry - radius), min(h, ry + radius + 1)):
                    if y == ry:
                        out[y, x] = 2
                    elif out[y, x] == 0:
                        out[y, x] = c
        elif direction == "right":
            for x in range(rx, w):
                for y in range(max(0, ry - radius), min(h, ry + radius + 1)):
                    if y == ry:
                        out[y, x] = 2
                    elif out[y, x] == 0:
