    rare_positions = []
    for r in range(grid.shape[0]):
        for c in range(grid.shape[1]):
            v = grid[r, c]
            if v != 0 and v != bg1 and v != bg2:
                rare_positions.append((r, c, v))

    if not rare_positions:
        return grid

    # Determine paint colors for each background from the rare cells.
    # The marker color itself is the paint color.
    # Associate by local neighborhood majority among the two backgrounds.
    def neighborhood_bg(r, c):
        rs = range(max(0, r - 1), min(grid.shape[0], r + 2))
        cs = range(max(0, c - 1), min(grid.shape[1], c + 2))
        n1 = n2 = 0
        for rr in rs:
            for cc in cs:
                if rr == r and cc == c:
                    continue
                if grid[rr, cc] == bg1:
                    n1 += 1
                elif grid[rr, cc] == bg2:
                    n2 += 1
        return bg1 if n1 >= n2 else bg2

