def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    g = np.array(input_grid)
    h, w = g.shape

    # Detect logical cell size by finding the smallest positive run length in rows/cols.
    def min_positive_run(arr):
        runs = []
        for line in arr:
            cnt = 0
            for x in line:
                if x != 0:
                    cnt += 1
                else:
                    if cnt > 0:
                        runs.append(cnt)
                    cnt = 0
            if cnt > 0:
                runs.append(cnt)
        return min(runs) if runs else 1

    cell_h = min_positive_run(g)
    cell_w = min_positive_run(g.T)

    # Compress each non-overlapping block into one logical cell by taking the most frequent nonzero color.
    rows = h // cell_h
    cols = w // cell_w
    small = np.zeros((rows, cols), dtype=int)

    for i in range(rows):
        for j in range(cols):
            block = g[i * cell_h:(i + 1) * cell_h, j * cell_w:(j + 1) * cell_w]
            vals = block[block != 0]
            if vals.size:
                colors, counts = np.unique(vals, return_counts=True)
                small[i, j] = colors[np.argmax(counts)]

    # Determine background as most frequent color in compressed matrix.
    colors, counts = np.unique(small, return_counts=True)
    bg = colors[np.argmax(counts)] if colors.size else 0

    # Count remaining colors and sort by frequency descending, then color value ascending.
    freq = {}
    for c in colors:
        if c == bg:
            continue
        freq[int(c)] = int(np.sum(small == c))

    ordered = sorted(freq.items(), key=lambda kv: (-kv[1], kv[0]))
    out = np.array([[c] for c, _ in ordered], dtype=int)
    return out

